#include<cstdio>
#include<vector>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=1e5+10;struct node{int l,r,sm;}t[N<<6];std::vector<int> IDX[N],G[N];
int Rt[N],cnt,n,m,top[N],fa[N],dep[N],siz[N],mxs[N],S[N],ans[N],p;
inline void update(const int &x){t[x].sm=t[t[x].l].sm+t[t[x].r].sm;}
inline void build(int &x,const int &l=1,const int &r=m){x=++cnt;if(l==r)return;int mid=(l+r)>>1;build(t[x].l,l,mid);build(t[x].r,mid+1,r);}
inline void add(int cur,int &x,const int &pos,const int &l=1,const int &r=m)
{
	t[x=++cnt]=t[cur];if(l==r){++t[x].sm;return;} const int &mid=(l+r)>>1;
	pos<=mid?add(t[cur].l,t[x].l,pos,l,mid):add(t[cur].r,t[x].r,pos,mid+1,r);update(x);
}
inline void qry(int Ru,int Rv,int Rl,int Rf,const int &k,const int &l=1,const int &r=m)
{
	if(!(t[Ru].sm+t[Rv].sm-t[Rl].sm-t[Rf].sm))return;
	if(l==r){ans[++p]=l;return;} const int &sl=t[t[Ru].l].sm+t[t[Rv].l].sm-t[t[Rl].l].sm-t[t[Rf].l].sm,&mid=(l+r)>>1;
	if(~k)k<=sl?qry(t[Ru].l,t[Rv].l,t[Rl].l,t[Rf].l,k,l,mid):(qry(t[Ru].l,t[Rv].l,t[Rl].l,t[Rf].l,-1,l,mid),qry(t[Ru].r,t[Rv].r,t[Rl].r,t[Rf].r,k-sl,mid+1,r));
	else{qry(t[Ru].l,t[Rv].l,t[Rl].l,t[Rf].l,-1,l,mid);qry(t[Ru].r,t[Rv].r,t[Rl].r,t[Rf].r,-1,mid+1,r);}
}
inline void dfs1(const int &u=1,const int &f=0)
{
	dep[u]=dep[fa[u]=f]+1;siz[u]=1;int mx=0;S[u]=S[f]+IDX[u].size();
	t[Rt[u]=++cnt]=t[Rt[f]];for(int v: IDX[u])add(Rt[u],Rt[u],v);
	for(int v:G[u])if(v!=f){dfs1(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
}
inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
{
	top[u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
	for(int v:G[u])if(v!=fa&&v!=mxs[u])dfs2(v,u,v);
}
inline int LCA(int u,int v){while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];return dep[u]<dep[v]?u:v;}
inline void debug(int cur,int l=1,int r=m)
{
	if(l==r)return printf("%d ",t[cur].sm),void();
	int mid=(l+r)>>1;debug(t[cur].l,l,mid);debug(t[cur].r,mid+1,r);
}
int main()
{
	n=read();m=read();int Q=read(); build(Rt[0]);
	rep(2,n,i){int u=read(),v=read();G[u].push_back(v);G[v].push_back(u);}
	rep(1,m,i)IDX[read()].push_back(i); dfs1();dfs2();
	while(Q--)
	{
		int u=read(),v=read(),l=LCA(u,v),k=min(read(),S[u]+S[v]-S[l]-S[fa[l]]);
		p=0;qry(Rt[u],Rt[v],Rt[l],Rt[fa[l]],k);
		printf("%d ",p);rep(1,p,i)printf("%d ",ans[i]);putchar('\n');
	}
}
